1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioOutput {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const DEDUCTIBLE = 100;
59	const CAP_MULTIPLIER = 2;
60	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
61	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
62	const CURSED_SURCHARGE_RATE = 0.5;
63	const HIGH_ENCHANTMENT_RATE = 0.3;
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	const FIRST_INSURANCE_RATE = 0.1;
66	const LOYALTY_DISCOUNT_RATE = 0.2;
67	const LOYALTY_YEARS_THRESHOLD = 2;
68	const FOLLOWUP_DISCOUNT_RATE = 0.15;
69	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
70	  sword: 100,
71	  amulet: 60,
72	  staff: 80,
73	  potion: 40,
74	  rune: 25,
75	  moonstone: 25,
76	};
77	
78	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
79	  sword: 1000,
80	  amulet: 600,
81	  staff: 800,
82	  potion: 400,
83	  rune: 250,
84	  moonstone: 250,
85	};
86	
87	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUM_BY_TYPE));
88	
89	const insuranceValue = (item: Item): number =>
90	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
91	
92	const insuranceSum = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + insuranceValue(item), 0);
94	
95	const basePremium = (item: Item): number =>
96	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
97	
98	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
99	
100	const groupByType = (items: Item[]): Map<string, Item[]> => {
101	  const groups = new Map<string, Item[]>();
102	  for (const item of items) {
103	    const existing = groups.get(item.type) ?? [];
104	    existing.push(item);
105	    groups.set(item.type, existing);
106	  }
107	  return groups;
108	};
109	
110	const sumBasePremiums = (items: Item[]): number =>
111	  items.reduce((sum, item) => sum + basePremium(item), 0);
112	
113	const isCompleteComponentBlock = (type: string, group: Item[]): boolean =>
114	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type);
115	
116	const groupTotal = (type: string, group: Item[]): number =>
117	  isCompleteComponentBlock(type, group)
118	    ? COMPONENT_BLOCK_PRICE
119	    : sumBasePremiums(group);
120	
121	const policyBase = (items: Item[]): number =>
122	  Array.from(groupByType(items)).reduce(
123	    (sum, [type, group]) => sum + groupTotal(type, group),
124	    0,
125	  );
126	
127	const perItemSurcharge = (
128	  items: Item[],
129	  predicate: (item: Item) => boolean,
130	  rate: number,
131	): number =>
132	  items.reduce(
133	    (sum, item) => sum + (predicate(item) ? basePremium(item) * rate : 0),
134	    0,
135	  );
136	
137	const isCursed = (item: Item): boolean => item.cursed === true;
138	
139	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
140	
141	const isHighlyEnchanted = (item: Item): boolean =>
142	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
143	
144	const firstInsuranceSurcharge = (base: number): number =>
145	  base * FIRST_INSURANCE_RATE;
146	
147	const loyaltyDiscount = (base: number, customer: Customer): number =>
148	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
149	    ? base * LOYALTY_DISCOUNT_RATE
150	    : 0;
151	
152	const followupDiscount = (base: number, quoteIndex: number): number =>
153	  quoteIndex > 0 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
154	
155	const totalSurcharges = (items: Item[], base: number): number =>
156	  perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE) +
157	  perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE) +
158	  firstInsuranceSurcharge(base);
159	
160	const totalDiscounts = (
161	  base: number,
162	  customer: Customer,
163	  quoteIndex: number,
164	): number =>
165	  loyaltyDiscount(base, customer) + followupDiscount(base, quoteIndex);
166	
167	const quotePremium = (
168	  items: Item[],
169	  customer: Customer,
170	  quoteIndex: number,
171	): number => {
172	  const base = policyBase(items);
173	  const adjusted =
174	    base +
175	    totalSurcharges(items, base) -
176	    totalDiscounts(base, customer, quoteIndex);
177	  return Math.ceil(adjusted) + PROCESSING_FEE;
178	};
179	
180	interface Policy {
181	  items: Item[];
182	  remainingCap: number;
183	}
184	
185	interface ScenarioState {
186	  customer: Customer;
187	  policies: Map<number, Policy>;
188	  quoteIndex: number;
189	  stepIndex: number;
190	}
191	
192	const validateItemTypes = (items: Item[]): void => {
193	  for (const item of items) {
194	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
195	      throw new Error(`unknown item type: ${item.type}`);
196	    }
197	  }
198	};
199	
200	const processQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
201	  validateItemTypes(step.items);
202	  state.policies.set(state.stepIndex, {
203	    items: step.items,
204	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
205	  });
206	  const premium = quotePremium(step.items, state.customer, state.quoteIndex);
207	  state.quoteIndex += 1;
208	  return { premium };
209	};
210	
211	const reimbursementRate = (item: Item): number =>
212	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
213	    ? HIGH_ENCHANTMENT_CLAIM_RATE
214	    : 1;
215	
216	const damagePayout = (damage: Damage, items: Item[]): number => {
217	  const item = items.find((it) => it.type === damage.itemType) as Item;
218	  return damage.amount * reimbursementRate(item) - DEDUCTIBLE;
219	};
220	
221	const countBy = <T>(items: T[], key: (item: T) => string): Map<string, number> => {
222	  const counts = new Map<string, number>();
223	  for (const item of items) {
224	    const k = key(item);
225	    counts.set(k, (counts.get(k) ?? 0) + 1);
226	  }
227	  return counts;
228	};
229	
230	const validateNonNegativeAmounts = (damages: Damage[]): void => {
231	  for (const damage of damages) {
232	    if (damage.amount < 0) {
233	      throw new Error(`claim damage amount must be non-negative`);
234	    }
235	  }
236	};
237	
238	const validateCoverage = (damages: Damage[], items: Item[]): void => {
239	  const itemCounts = countBy(items, (item) => item.type);
240	  const damageCounts = countBy(damages, (damage) => damage.itemType);
241	  for (const [type, count] of damageCounts) {
242	    if (count > (itemCounts.get(type) ?? 0)) {
243	      throw new Error(
244	        `claim damages exceed policy coverage for itemType ${type}`,
245	      );
246	    }
247	  }
248	};
249	
250	const validateDamages = (damages: Damage[], items: Item[]): void => {
251	  validateNonNegativeAmounts(damages);
252	  validateCoverage(damages, items);
253	};
254	
255	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
256	  damages.reduce((sum, damage) => sum + damagePayout(damage, items), 0);
257	
258	const processClaim = (step: ClaimStep, state: ScenarioState): ClaimResult => {
259	  const policy = state.policies.get(step.policy) as Policy;
260	  validateDamages(step.incident.damages, policy.items);
261	  const rawPayout = sumDamagePayouts(step.incident.damages, policy.items);
262	  const payout = Math.floor(Math.min(rawPayout, policy.remainingCap));
263	  policy.remainingCap -= payout;
264	  return { payout, remainingCap: policy.remainingCap };
265	};
266	
267	const processStep = (step: Step, state: ScenarioState): StepResult =>
268	  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);
269	
270	export const processScenario = (scenario: Scenario): ScenarioOutput => {
271	  const state: ScenarioState = {
272	    customer: scenario.customer,
273	    policies: new Map<number, Policy>(),
274	    quoteIndex: 0,
275	    stepIndex: 0,
276	  };
277	  const results: StepResult[] = scenario.steps.map((step, stepIndex) => {
278	    state.stepIndex = stepIndex;
279	    return processStep(step, state);
280	  });
281	  return { results };
282	};
